//-------------------------------------------------------------------------
// 그리드 이벤트
//-------------------------------------------------------------------------
scwin.gr_dnTrustTaxInvoice_onheaderclick = function (headerId) {
  var i = 0;
  var bCheck = gr_dnTrustTaxInvoice.getHeaderValue("column1"); // 체크 여부

  if (headerId == "column1") {
    if (bCheck == true) {
      for (var i = 0; i < ds_dnTrustTaxInvoice.getTotalRow(); i++) {
        ds_dnTrustTaxInvoice.setCellData(i, "choice", "T");
      }
    } else {
      for (var i = 0; i < ds_dnTrustTaxInvoice.getTotalRow(); i++) {
        ds_dnTrustTaxInvoice.setCellData(i, "choice", "F");
      }
    }
  }
};
scwin.gr_dnTrustTaxInvoice_oncellclick = async function (rowIndex, columnIndex, columnId) {
  if (columnId == "button" && rowIndex >= 0) {
    ds_dnTrustTaxInvoice.setCellData(rowIndex, "choice", "T");
    var valueObject = new Object();
    valueObject.pchsClntNo = ds_dnTrustTaxInvoice.getCellData(rowIndex, "bilgClntNo");
    valueObject.certiNo = ds_dnTrustTaxInvoice.getCellData(rowIndex, "certiNo");
    valueObject.homeClntNo = ds_dnTrustTaxInvoice.getCellData(rowIndex, "homeClntNo");
    valueObject.acctGubun = ds_dnTrustTaxInvoice.getCellData(rowIndex, "acctGubun");
    valueObject.oldBilgClntNo = ds_dnTrustTaxInvoice.getCellData(rowIndex, "oldBilgClntNo");
    var opts = {
      id: "smpPop",
      popupName: "대납전표개별생성",
      modal: true,
      type: "browserPopup",
      width: 840,
      height: 440,
      title: "대납전표개별생성"
    };
    $c.win.openPopup($p, "/ui/ja/dnja/consignmgnt/dnja_210_03_02p.xml", opts, valueObject);
    let e = await $c.sbm.execute($p, sbm_searchCertiList);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
      scwin.sbm_searchCertiList_submitdone(e);
    }
  }
};

//-------------------------------------------------------------------------
// Formatter
//-------------------------------------------------------------------------
scwin.f_gr_dnTrustTaxInvoice_customFormatter = function (data, formattedData, rowIndex, colIndex) {
  let columnId = $c.util.getComponent($p, this.id).getColumnID(colIndex);
  let val = data,
    color = "black";
  var slipNo = ds_dnTrustTaxInvoice.getCellData(rowIndex, "slipNo");
  if (columnId == "acctGubun") {
    if (slipNo == "") {
      if (data == 0) {
        val = "전도금";
      } else {
        val = "미지급금";
      }
    } else {
      val = "";
    }
  }
  return val;
};
scwin.gr_dnTrustTaxInvoice_onbeforecolumnmove = function (info) {
  const validArr = ["choice", "button", "slipNo"];
  const startColumnID = info.startColumnID;
  const endColumnID = info.endColumnID;
  if ($.inArray(startColumnID, validArr) > -1) {
    return false;
  }
  if ($.inArray(endColumnID, validArr) > -1) {
    return false;
  }
};
